import { Check, ChevronsUpDown, Pencil } from "lucide-react";
import { Fragment, useMemo, useState } from "react";

import { Button } from "@/components/ui/button";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
  CommandSeparator,
} from "@/components/ui/command";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { cn } from "@/lib/utils";

import type { FieldOption } from "fastschema";

export interface FieldSelectProps {
  value?: string;
  onChange?: (value: string, fieldOption: FieldOption) => void;
  options: FieldOption[];
  placeholder?: string;
  disabled?: boolean;
  className?: string;
  allowCustomField?: boolean;
}

export function FieldSelect({
  value,
  onChange,
  options,
  placeholder = "Select field...",
  disabled = false,
  className,
  allowCustomField = true,
}: FieldSelectProps) {
  const [open, setOpen] = useState(false);
  const [customFieldDialogOpen, setCustomFieldDialogOpen] = useState(false);
  const [customFieldPath, setCustomFieldPath] = useState("");

  const selectedOption = useMemo(
    () => options.find((o) => o.value === value),
    [options, value],
  );

  // Check if current value is a custom field (not in options)
  const isCustomField = value && !selectedOption;

  // Group options by depth
  const groupedOptions = useMemo(() => {
    const direct = options.filter((o) => o.depth === 0 && !o.isCustomField);
    const relation = options.filter((o) => o.depth > 0 && !o.isCustomField);
    const custom = options.filter((o) => o.isCustomField);
    return { direct, relation, custom };
  }, [options]);

  const handleSelect = (optionValue: string) => {
    const option = options.find((o) => o.value === optionValue);
    if (option) {
      onChange?.(optionValue, option);
    }
    setOpen(false);
  };

  const handleCustomFieldSubmit = () => {
    if (customFieldPath.trim()) {
      // Create a custom field option
      const customOption: FieldOption = {
        value: customFieldPath.trim(),
        label: customFieldPath.trim(),
        type: "string", // Default to string for custom fields
        fieldDef: {
          name: customFieldPath.trim(),
          label: customFieldPath.trim(),
          type: "string",
        },
        isRelationField: customFieldPath.includes("."),
        isCustomField: true,
        depth: customFieldPath.split(".").length - 1,
      };
      onChange?.(customFieldPath.trim(), customOption);
      setCustomFieldDialogOpen(false);
      setCustomFieldPath("");
      setOpen(false);
    }
  };

  const displayLabel =
    selectedOption?.label || (isCustomField ? value : placeholder);

  return (
    <Fragment>
      <Popover
        open={open}
        onOpenChange={setOpen}
        modal
      >
        <PopoverTrigger asChild>
          <Button
            variant="outline"
            role="combobox"
            aria-expanded={open}
            disabled={disabled}
            className={cn(
              "h-8 w-[120px] justify-between font-normal",
              !value && "text-muted-foreground",
              isCustomField && "italic",
              className,
            )}
          >
            <span className="truncate">{displayLabel}</span>
            <ChevronsUpDown className="ml-1 h-4 w-4 shrink-0 opacity-50" />
          </Button>
        </PopoverTrigger>
        <PopoverContent
          className="w-[280px] p-0"
          align="start"
        >
          <Command>
            <CommandInput placeholder="Search fields..." />
            <CommandList>
              <CommandEmpty>No fields found.</CommandEmpty>
              {groupedOptions.direct.length > 0 && (
                <CommandGroup heading="Fields">
                  {groupedOptions.direct.map((option) => (
                    <CommandItem
                      key={option.value}
                      value={option.value}
                      onSelect={handleSelect}
                    >
                      <Check
                        className={cn(
                          "mr-2 h-4 w-4",
                          value === option.value ? "opacity-100" : "opacity-0",
                        )}
                      />
                      <span className="flex-1 truncate">{option.label}</span>
                      <span className="text-muted-foreground ml-2 text-xs">
                        {option.fieldDef.type}
                      </span>
                    </CommandItem>
                  ))}
                </CommandGroup>
              )}
              {groupedOptions.relation.length > 0 && (
                <CommandGroup heading="Relation Fields">
                  {groupedOptions.relation.map((option) => (
                    <CommandItem
                      key={option.value}
                      value={option.value}
                      onSelect={handleSelect}
                    >
                      <Check
                        className={cn(
                          "mr-2 h-4 w-4",
                          value === option.value ? "opacity-100" : "opacity-0",
                        )}
                      />
                      <span className="flex-1 truncate">{option.label}</span>
                      <span className="text-muted-foreground ml-2 text-xs">
                        {option.fieldDef.type}
                      </span>
                    </CommandItem>
                  ))}
                </CommandGroup>
              )}
              {allowCustomField && (
                <Fragment>
                  <CommandSeparator />
                  <CommandGroup heading="Advanced">
                    <CommandItem
                      onSelect={() => {
                        setCustomFieldPath(value || "");
                        setCustomFieldDialogOpen(true);
                      }}
                    >
                      <Pencil className="mr-2 h-4 w-4" />
                      <span>Custom field path...</span>
                    </CommandItem>
                  </CommandGroup>
                </Fragment>
              )}
            </CommandList>
          </Command>
        </PopoverContent>
      </Popover>

      <Dialog
        open={customFieldDialogOpen}
        onOpenChange={setCustomFieldDialogOpen}
      >
        <DialogContent className="sm:max-w-[425px]">
          <DialogHeader>
            <DialogTitle>Custom Field Path</DialogTitle>
            <DialogDescription>
              Enter a custom field path for filtering. Use dot notation for
              nested fields (e.g., <code>categories.posts.slug</code>).
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="grid gap-2">
              <Label htmlFor="fieldPath">Field Path</Label>
              <Input
                id="fieldPath"
                placeholder="e.g., categories.posts.slug"
                value={customFieldPath}
                onChange={(e) => setCustomFieldPath(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    handleCustomFieldSubmit();
                  }
                }}
              />
              <p className="text-muted-foreground text-xs">
                Examples: <code>name</code>, <code>author.email</code>,{" "}
                <code>categories.posts.title</code>
              </p>
            </div>
          </div>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setCustomFieldDialogOpen(false)}
            >
              Cancel
            </Button>
            <Button
              onClick={handleCustomFieldSubmit}
              disabled={!customFieldPath.trim()}
            >
              Apply
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </Fragment>
  );
}

import {
  createFilterCondition,
  createFilterGroup,
  isFilterCondition,
  isFilterGroup,
  type FieldOption,
  type FilterCondition,
  type FilterGroup,
} from "fastschema";
import { Plus, Trash2 } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { cn } from "@/lib/utils";

import { FilterRow } from "./filter-row";

export interface FilterGroupComponentProps {
  group: FilterGroup;
  fieldOptions: FieldOption[];
  depth?: number;
  onChange: (group: FilterGroup) => void;
  onRemove?: () => void;
  disabled?: boolean;
  className?: string;
  showGroupControls?: boolean;
}

export function FilterGroupComponent({
  group,
  fieldOptions,
  depth = 0,
  onChange,
  onRemove,
  disabled = false,
  className,
  showGroupControls = true,
}: FilterGroupComponentProps) {
  // Add a new condition to this group
  const handleAddCondition = () => {
    const newCondition = createFilterCondition();
    onChange({
      ...group,
      conditions: [...group.conditions, newCondition],
    });
  };

  // Add a nested group
  const handleAddGroup = () => {
    const newGroup = createFilterGroup(
      group.logicalOperator === "$and" ? "$or" : "$and",
    );
    onChange({
      ...group,
      conditions: [...group.conditions, newGroup],
    });
  };

  // Update a condition at index
  const handleUpdateCondition = (
    index: number,
    updatedCondition: FilterCondition,
  ) => {
    const newConditions = [...group.conditions];
    newConditions[index] = updatedCondition;
    onChange({
      ...group,
      conditions: newConditions,
    });
  };

  // Update a nested group at index
  const handleUpdateGroup = (index: number, updatedGroup: FilterGroup) => {
    const newConditions = [...group.conditions];
    newConditions[index] = updatedGroup;
    onChange({
      ...group,
      conditions: newConditions,
    });
  };

  // Remove a condition/group at index
  const handleRemove = (index: number) => {
    const newConditions = group.conditions.filter((_, i) => i !== index);
    onChange({
      ...group,
      conditions: newConditions,
    });
  };

  // Change logical operator
  const handleLogicalOperatorChange = (op: "$and" | "$or") => {
    onChange({
      ...group,
      logicalOperator: op,
    });
  };

  const isNested = depth > 0;

  return (
    <div
      className={cn(
        "space-y-2",
        isNested &&
          "border-muted-foreground/30 bg-muted/20 rounded-lg border border-dashed p-3",
        className,
      )}
    >
      {/* Group header for nested groups */}
      {isNested && showGroupControls && (
        <div className="mb-2 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Select
              value={group.logicalOperator}
              onValueChange={(v) =>
                handleLogicalOperatorChange(v as "$and" | "$or")
              }
              disabled={disabled}
            >
              <SelectTrigger
                className="h-8 w-18 text-xs"
                size="sm"
              >
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="$and">And</SelectItem>
                <SelectItem value="$or">Or</SelectItem>
              </SelectContent>
            </Select>
            <span className="text-muted-foreground text-sm font-medium">
              {group.logicalOperator === "$and" ? "All" : "Any"} Of
            </span>
          </div>
          {onRemove && (
            <Button
              type="button"
              variant="ghost"
              size="sm"
              className="text-muted-foreground hover:text-destructive"
              onClick={onRemove}
              disabled={disabled}
            >
              <Trash2 className="h-3 w-3" />
            </Button>
          )}
        </div>
      )}

      {/* Conditions and nested groups */}
      <div className="space-y-2">
        {group.conditions.map((item, index) => {
          if (isFilterCondition(item)) {
            return (
              <FilterRow
                key={item.id}
                condition={item}
                fieldOptions={fieldOptions}
                showLogicalOperator={!isNested && index > 0}
                logicalOperator={group.logicalOperator}
                onLogicalOperatorChange={
                  index === 1 ? handleLogicalOperatorChange : undefined
                }
                onChange={(updated) => handleUpdateCondition(index, updated)}
                onRemove={() => handleRemove(index)}
                isFirst={index === 0 && !isNested}
                disabled={disabled}
              />
            );
          }

          if (isFilterGroup(item)) {
            return (
              <FilterGroupComponent
                key={item.id}
                group={item}
                fieldOptions={fieldOptions}
                depth={depth + 1}
                onChange={(updated) => handleUpdateGroup(index, updated)}
                onRemove={() => handleRemove(index)}
                disabled={disabled}
              />
            );
          }

          return null;
        })}
      </div>

      {/* Add buttons */}
      {showGroupControls && (
        <div className="flex items-center gap-2 pt-2">
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-8"
            onClick={handleAddCondition}
            disabled={disabled}
          >
            <Plus className="mr-1 h-4 w-4" />
            Add filter
          </Button>
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-8"
            onClick={handleAddGroup}
            disabled={disabled}
          >
            <Plus className="mr-1 h-4 w-4" />
            Add group
          </Button>
        </div>
      )}

      {/* Empty state */}
      {group.conditions.length === 0 && (
        <div className="text-muted-foreground flex items-center justify-center py-6 text-sm">
          No filters added. Click &quot;Add filter&quot; to get started.
        </div>
      )}
    </div>
  );
}

import {
  getDefaultOperatorForFieldType,
  getOperatorsForFieldType,
  type FieldOption,
  type FilterCondition,
  type OperatorOption,
} from "fastschema";
import { GripVertical, Trash2 } from "lucide-react";
import { useMemo, useState } from "react";

import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { cn } from "@/lib/utils";

import { FieldSelect } from "./field-select";
import { FilterValueInput } from "./filter-value-input";
import { OperatorSelect } from "./operator-select";

export interface FilterRowProps {
  condition: FilterCondition;
  fieldOptions: FieldOption[];
  showLogicalOperator: boolean;
  logicalOperator: "$and" | "$or";
  onLogicalOperatorChange?: (op: "$and" | "$or") => void;
  onChange: (condition: FilterCondition) => void;
  onRemove: () => void;
  isFirst: boolean;
  disabled?: boolean;
  className?: string;
}

export function FilterRow({
  condition,
  fieldOptions,
  showLogicalOperator,
  logicalOperator,
  onLogicalOperatorChange,
  onChange,
  onRemove,
  isFirst,
  disabled = false,
  className,
}: FilterRowProps) {
  // Track custom field option separately
  const [customFieldOption, setCustomFieldOption] =
    useState<FieldOption | null>(null);

  // Find current field option (from options or custom)
  const currentFieldOption = useMemo(() => {
    // First check if we have a custom field option that matches
    if (customFieldOption && customFieldOption.value === condition.fieldPath) {
      return customFieldOption;
    }
    // Otherwise look in the provided options
    return fieldOptions.find((f) => f.value === condition.fieldPath);
  }, [fieldOptions, condition.fieldPath, customFieldOption]);

  // Get available operators for selected field
  const operatorOptions = useMemo(() => {
    if (!currentFieldOption) {
      return [];
    }
    return getOperatorsForFieldType(
      currentFieldOption.fieldDef.type,
      currentFieldOption.isCustomField,
    );
  }, [currentFieldOption]);

  // Handle field change
  const handleFieldChange = (fieldPath: string, fieldOption: FieldOption) => {
    // If it's a custom field, save it
    if (fieldOption.isCustomField) {
      setCustomFieldOption(fieldOption);
    } else {
      setCustomFieldOption(null);
    }

    const defaultOperator = getDefaultOperatorForFieldType(
      fieldOption.fieldDef.type,
      fieldOption.isCustomField,
    );
    onChange({
      ...condition,
      fieldPath,
      operator: defaultOperator,
      value: undefined, // Reset value when field changes
    });
  };

  // Handle operator change
  const handleOperatorChange = (
    operator: FilterCondition["operator"],
    _option: OperatorOption,
  ) => {
    // Reset value when switching between single/array/range operators
    const currentOp = operatorOptions.find(
      (o: OperatorOption) => o.value === condition.operator,
    );
    const newOp = operatorOptions.find(
      (o: OperatorOption) => o.value === operator,
    );

    const shouldResetValue =
      currentOp?.valueCount !== newOp?.valueCount ||
      currentOp?.isArrayOperator !== newOp?.isArrayOperator;

    onChange({
      ...condition,
      operator,
      value: shouldResetValue ? undefined : condition.value,
    });
  };

  // Handle value change
  const handleValueChange = (value: FilterCondition["value"]) => {
    onChange({
      ...condition,
      value,
    });
  };

  return (
    <div
      className={cn(
        "bg-muted/30 flex items-center gap-2 rounded-md border p-2",
        className,
      )}
    >
      {/* Drag handle */}
      <div className="flex-shrink-0 cursor-grab opacity-50 hover:opacity-100">
        <GripVertical className="h-4 w-4" />
      </div>

      {/* Logical operator or "Where" label */}
      <div className="flex-shrink-0">
        {isFirst ? (
          <span className="text-muted-foreground flex h-8 w-19 items-center justify-start pl-1 text-sm">
            Where
          </span>
        ) : showLogicalOperator ? (
          <Select
            value={logicalOperator}
            onValueChange={(v) =>
              onLogicalOperatorChange?.(v as "$and" | "$or")
            }
            disabled={disabled}
          >
            <SelectTrigger
              className="h-8 w-19"
              size="sm"
            >
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="$and">And</SelectItem>
              <SelectItem value="$or">Or</SelectItem>
            </SelectContent>
          </Select>
        ) : (
          <span className="text-muted-foreground flex h-8 w-8 items-center justify-start text-sm">
            {logicalOperator === "$or" ? "Or" : "And"}
          </span>
        )}
      </div>

      {/* Field select */}
      <FieldSelect
        value={condition.fieldPath}
        onChange={handleFieldChange}
        options={fieldOptions}
        disabled={disabled}
        className="flex-shrink-0"
      />

      {/* Operator select */}
      <OperatorSelect
        value={condition.operator}
        onChange={handleOperatorChange}
        options={operatorOptions}
        disabled={disabled || !condition.fieldPath}
        className="flex-shrink-0"
      />

      {/* Value input */}
      <div className="min-w-[160px] flex-1">
        {currentFieldOption ? (
          <FilterValueInput
            fieldDef={currentFieldOption.fieldDef}
            operator={condition.operator}
            value={condition.value}
            onChange={handleValueChange}
            disabled={disabled || !condition.fieldPath}
            isCustomField={currentFieldOption.isCustomField}
          />
        ) : (
          <div className="border-muted-foreground/30 flex h-8 items-center justify-center rounded-md border border-dashed">
            <span className="text-muted-foreground text-xs">
              Select a field first
            </span>
          </div>
        )}
      </div>

      {/* Remove button */}
      <Button
        type="button"
        variant="ghost"
        size="icon"
        className="text-muted-foreground hover:text-destructive h-8 w-8 flex-shrink-0"
        onClick={onRemove}
        disabled={disabled}
      >
        <Trash2 className="h-4 w-4" />
      </Button>
    </div>
  );
}

import {
  getFieldTypeCategory,
  type Entity,
  type ExtendedFilterOperator,
  type FieldDefinition,
  type FieldTypeCategory,
  type FilterValue,
  type RelationFieldDefinition,
} from "fastschema";

import { RelationPicker } from "@/components/fsui/fspage-content-list";

import {
  BooleanInput,
  DateRangePicker,
  DateTimePicker,
  EnumSelect,
  JsonInput,
  MultiValueInput,
  NullInput,
  NumberInput,
  NumberRangeInput,
  TextInput,
} from "./value-inputs";

/** Partial field definition that includes required fields for filter value input */
export type PartialFieldDefinition = Partial<FieldDefinition> & {
  name: string;
  type: string;
};

export interface FilterValueInputProps {
  fieldDef: PartialFieldDefinition;
  operator: ExtendedFilterOperator;
  value?: FilterValue;
  onChange?: (value: FilterValue) => void;
  disabled?: boolean;
  className?: string;
  isCustomField?: boolean;
}

function renderBetweenInput(
  category: FieldTypeCategory,
  fieldDef: PartialFieldDefinition,
  value: FilterValue,
  onChange?: (value: FilterValue) => void,
  disabled?: boolean,
  className?: string,
) {
  const rangeValue = Array.isArray(value) ? value : [undefined, undefined];

  switch (category) {
    case "number": {
      return (
        <NumberRangeInput
          value={rangeValue as [number | undefined, number | undefined]}
          onChange={(v) => onChange?.(v as FilterValue)}
          disabled={disabled}
          className={className}
          allowFloat={["float32", "float64"].includes(fieldDef.type)}
        />
      );
    }
    case "datetime": {
      return (
        <DateRangePicker
          value={rangeValue as [Date | undefined, Date | undefined]}
          onChange={(v) => onChange?.(v as FilterValue)}
          disabled={disabled}
          className={className}
          showTime
        />
      );
    }
    default: {
      // Fallback to number range for unsupported types
      return (
        <NumberRangeInput
          value={rangeValue as [number | undefined, number | undefined]}
          onChange={(v) => onChange?.(v as FilterValue)}
          disabled={disabled}
          className={className}
        />
      );
    }
  }
}

function renderArrayInput(
  category: FieldTypeCategory,
  fieldDef: PartialFieldDefinition,
  value: FilterValue,
  onChange?: (value: FilterValue) => void,
  disabled?: boolean,
  className?: string,
) {
  const arrayValue = Array.isArray(value) ? value : [];

  switch (category) {
    case "enum": {
      return (
        <EnumSelect
          value={arrayValue as string[]}
          onChange={(v) => onChange?.(v as FilterValue)}
          options={fieldDef.enums || []}
          multiple
          disabled={disabled}
          className={className}
        />
      );
    }
    case "relation": {
      return (
        <RelationPicker
          schemaName={fieldDef.relation?.schema || ""}
          relationField={fieldDef as unknown as RelationFieldDefinition}
          value={arrayValue as unknown as Entity[]}
          onSelectionChange={(v) => onChange?.(v as unknown as FilterValue)}
          multiple
          disabled={disabled}
          className={className}
        />
      );
    }
    case "number": {
      return (
        <MultiValueInput
          value={arrayValue as number[]}
          onChange={(v) => onChange?.(v as FilterValue)}
          type="number"
          disabled={disabled}
          className={className}
        />
      );
    }
    default: {
      return (
        <MultiValueInput
          value={arrayValue as string[]}
          onChange={(v) => onChange?.(v as FilterValue)}
          type="text"
          disabled={disabled}
          className={className}
        />
      );
    }
  }
}

function renderSingleInput(
  category: FieldTypeCategory,
  fieldDef: PartialFieldDefinition,
  value: FilterValue,
  onChange?: (value: FilterValue) => void,
  disabled?: boolean,
  className?: string,
) {
  switch (category) {
    case "text": {
      return (
        <TextInput
          value={value as string}
          onChange={(v) => onChange?.(v)}
          disabled={disabled}
          className={className}
        />
      );
    }
    case "number": {
      return (
        <NumberInput
          value={value as number}
          onChange={(v) => onChange?.(v)}
          disabled={disabled}
          className={className}
          allowFloat={["float32", "float64"].includes(fieldDef.type)}
        />
      );
    }
    case "boolean": {
      return (
        <BooleanInput
          value={value as boolean}
          onChange={(v) => onChange?.(v)}
          disabled={disabled}
          className={className}
        />
      );
    }
    case "datetime": {
      return (
        <DateTimePicker
          value={
            value instanceof Date
              ? value
              : value
                ? new Date(value as string)
                : undefined
          }
          onChange={(v) => onChange?.(v)}
          disabled={disabled}
          className={className}
          showTime
        />
      );
    }
    case "enum": {
      return (
        <EnumSelect
          value={value as string}
          onChange={(v) => onChange?.(Array.isArray(v) ? v[0] : v)}
          options={fieldDef.enums || []}
          multiple={false}
          disabled={disabled}
          className={className}
        />
      );
    }
    case "relation": {
      return (
        <RelationPicker
          schemaName={fieldDef.relation?.schema || ""}
          relationField={fieldDef as unknown as RelationFieldDefinition}
          value={(value ? [{ id: value }] : []) as Entity[]}
          onSelectionChange={(v) => onChange?.(v[0]?.id)}
          multiple={false}
          disabled={disabled}
          className={className}
        />
      );
    }
    default: {
      return (
        <TextInput
          value={String(value ?? "")}
          onChange={(v) => onChange?.(v)}
          disabled={disabled}
          className={className}
        />
      );
    }
  }
}

export function FilterValueInput({
  fieldDef,
  operator,
  value,
  onChange,
  disabled = false,
  className,
  isCustomField = false,
}: FilterValueInputProps) {
  const category = getFieldTypeCategory(fieldDef.type);

  // Handle $null operator - special case
  if (operator === "$null") {
    return (
      <NullInput
        value={value as boolean}
        onChange={(v) => onChange?.(v)}
        disabled={disabled}
        className={className}
      />
    );
  }

  // Custom fields always use JSON input for flexibility
  if (isCustomField) {
    return (
      <JsonInput
        value={value}
        onChange={(v) => onChange?.(v)}
        disabled={disabled}
        className={className}
        placeholder={
          operator === "$in" || operator === "$nin"
            ? '["a", "b"] or [1, 2]'
            : operator === "$between"
              ? "[min, max]"
              : '"text", 123, true'
        }
      />
    );
  }

  // Handle $between operator
  if (operator === "$between") {
    return renderBetweenInput(
      category,
      fieldDef,
      value,
      onChange,
      disabled,
      className,
    );
  }

  // Handle array operators ($in, $nin)
  if (operator === "$in" || operator === "$nin") {
    return renderArrayInput(
      category,
      fieldDef,
      value,
      onChange,
      disabled,
      className,
    );
  }

  // Handle single value operators
  return renderSingleInput(
    category,
    fieldDef,
    value,
    onChange,
    disabled,
    className,
  );
}

