import {
  buildContentListFilter,
  countActiveFilters,
  createEmptyFilterState,
  createFilterCondition,
  createFilterGroup,
  createFilterFieldOptions,
  parseFilterToState,
  validateFilterState,
  type FieldOption,
  type Filter,
  type FilterState,
  type SchemaDefinition,
} from "fastschema";
import { useFastSchema } from "fastschema/react";
import { useCallback, useEffect, useMemo, useState } from "react";

export interface ContentFilterProps {
  schemaDefinition: SchemaDefinition;
  storageKey?: string;
  initialFilter?: Filter;
  includeRelationFields?: boolean;
  allowCustomFields?: boolean;
  persist?: "localStorage" | "none";
  onChange?: (filter: Filter | undefined) => void;
}

const STORAGE_PREFIX = "fsfilter_";

export const syncStorageToFilterState = ({
  fieldOptions,
  storageKey,
  initialFilter,
  persist = "none",
}: {
  fieldOptions: FieldOption[];
  storageKey?: string;
  initialFilter?: Filter;
  persist?: "localStorage" | "none";
}) => {
  if (storageKey && persist === "localStorage") {
    try {
      const stored = localStorage.getItem(STORAGE_PREFIX + storageKey);
      if (stored) {
        const parsed = JSON.parse(stored);
        return parseFilterToState(parsed, fieldOptions);
      }
    } catch (error) {
      // eslint-disable-next-line no-console
      console.error(
        `Failed to load filter state from localStorage for key: ${storageKey}`,
        error,
      );
    }
  }

  return initialFilter
    ? parseFilterToState(initialFilter, fieldOptions)
    : createEmptyFilterState();
};

export const syncFilterStateToStorage = (
  state: FilterState,
  storageKey?: string,
  persist: "localStorage" | "none" = "none",
) => {
  if (storageKey && persist === "localStorage") {
    try {
      const filter = buildContentListFilter(state);
      if (filter) {
        localStorage.setItem(
          STORAGE_PREFIX + storageKey,
          JSON.stringify(filter),
        );
      } else {
        localStorage.removeItem(STORAGE_PREFIX + storageKey);
      }
    } catch (error) {
      // eslint-disable-next-line no-console
      console.error(
        `Failed to save filter state to localStorage for key: ${storageKey}`,
        error,
      );
    }
  }
};

export const resetFilterStateStorage = (storageKey?: string) => {
  if (storageKey) {
    localStorage.removeItem(STORAGE_PREFIX + storageKey);
  }
};

export const useContentFilter = ({
  schemaDefinition,
  includeRelationFields,
  initialFilter,
  storageKey,
  persist = "none",
  onChange,
}: ContentFilterProps) => {
  const [isOpen, setIsOpen] = useState(false);
  const { fastschema } = useFastSchema();
  const fieldOptions = useMemo(() => {
    return createFilterFieldOptions({
      fastschema,
      schemaDefinition,
      includeRelationFields,
    });
  }, [schemaDefinition, fastschema, includeRelationFields]);

  // Load initial state from localStorage or initialFilter
  const [state, setState] = useState(
    syncStorageToFilterState({
      storageKey,
      initialFilter,
      fieldOptions,
      persist,
    }),
  );

  // Save to localStorage when state changes
  useEffect(() => {
    syncFilterStateToStorage(state, storageKey, persist);
  }, [state, storageKey, persist]);

  const addCondition = () => {
    setState({
      root: {
        ...state.root,
        conditions: [...state.root.conditions, createFilterCondition()],
      },
    });
  };

  const addGroup = () => {
    setState({
      root: {
        ...state.root,
        conditions: [
          ...state.root.conditions,
          createFilterGroup(
            state.root.logicalOperator === "$and" ? "$or" : "$and",
          ),
        ],
      },
    });
  };

  // Reset all filters
  const resetFilter = useCallback(() => {
    setState(createEmptyFilterState());
    resetFilterStateStorage(storageKey);
    onChange?.(undefined);
    setIsOpen(false);
  }, [storageKey, onChange]);

  // Apply filter (build and call onChange)
  const applyFilter = useCallback(() => {
    const validationErrors = validateFilterState(state, fieldOptions);
    if (validationErrors.length > 0) {
      // eslint-disable-next-line no-console
      console.error("Filter validation errors:", validationErrors);
    }
    const filter = buildContentListFilter(state);
    onChange?.(filter);
    setIsOpen(false);
    return filter;
  }, [state, fieldOptions, onChange]);

  return {
    state,
    setState,
    addCondition,
    addGroup,
    resetFilter,
    buildContentListFilter,
    applyFilter,
    activeFilterCount: useMemo(() => countActiveFilters(state), [state]),
    fieldOptions,
    isOpen,
    setIsOpen,
  };
};

