export interface DateTimePickerProps {
  value?: Date;
  onChange?: (date: Date | undefined) => void;
  placeholder?: string;
  disabled?: boolean;
  className?: string;
  showTime?: boolean;
  clearable?: boolean;
}

export function DateTimePicker({
  value,
  onChange,
  placeholder = "Select date",
  disabled = false,
  className,
  showTime = true,
  clearable = true,
}: DateTimePickerProps) {
  const [open, setOpen] = React.useState(false);
  const [selectedDate, setSelectedDate] = React.useState<Date | undefined>(
    value,
  );

  // Sync with external value
  React.useEffect(() => {
    setSelectedDate(value);
  }, [value]);

  const handleDateSelect = (date: Date | undefined) => {
    if (!date) {
      setSelectedDate(undefined);
      onChange?.(undefined);
      return;
    }

    // Preserve time if we already have a selected date
    if (selectedDate && showTime) {
      date.setHours(selectedDate.getHours());
      date.setMinutes(selectedDate.getMinutes());
      date.setSeconds(selectedDate.getSeconds());
    }

    setSelectedDate(date);
    onChange?.(date);

    // Close popover if not showing time
    if (!showTime) {
      setOpen(false);
    }
  };

  const handleTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const timeValue = e.target.value;
    if (!timeValue) return;

    const [hours, minutes] = timeValue.split(":").map(Number);
    const newDate = selectedDate ? new Date(selectedDate) : new Date();

    newDate.setHours(hours);
    newDate.setMinutes(minutes);
    newDate.setSeconds(0);

    setSelectedDate(newDate);
    onChange?.(newDate);
  };

  const handleClear = (e: React.MouseEvent) => {
    e.stopPropagation();
    setSelectedDate(undefined);
    onChange?.(undefined);
  };

  const formatDateTime = (date: Date) => {
    if (showTime) {
      return format(date, "PPP HH:mm");
    }
    return format(date, "PPP");
  };

  const getTimeValue = () => {
    if (!selectedDate) return "";
    const hours = selectedDate.getHours().toString().padStart(2, "0");
    const minutes = selectedDate.getMinutes().toString().padStart(2, "0");
    return `${hours}:${minutes}`;
  };

  return (
    <Popover
      open={open}
      onOpenChange={setOpen}
    >
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          disabled={disabled}
          data-empty={!selectedDate}
          className={cn(
            "data-[empty=true]:text-muted-foreground w-full justify-start text-left font-normal",
            className,
          )}
        >
          <CalendarIcon className="mr-2 h-4 w-4" />
          {selectedDate ? formatDateTime(selectedDate) : placeholder}
          {clearable && selectedDate && (
            <X
              className="ml-auto h-4 w-4 opacity-50 hover:opacity-100"
              onClick={handleClear}
            />
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent
        className="w-auto overflow-hidden p-0"
        align="start"
      >
        <Calendar
          mode="single"
          selected={selectedDate}
          onSelect={handleDateSelect}
          captionLayout="dropdown"
        />
        {showTime && (
          <div className="border-t p-3">
            <div className="flex items-center gap-2">
              <span className="text-muted-foreground text-sm">Time:</span>
              <Input
                type="time"
                value={getTimeValue()}
                onChange={handleTimeChange}
                className="bg-background w-auto appearance-none [&::-webkit-calendar-picker-indicator]:hidden [&::-webkit-calendar-picker-indicator]:appearance-none"
              />
              <Button
                variant="outline"
                size="sm"
                onClick={() => {
                  const now = new Date();
                  setSelectedDate(now);
                  onChange?.(now);
                }}
              >
                Now
              </Button>
            </div>
          </div>
        )}
      </PopoverContent>
    </Popover>
  );
}

