/**
 * JSON input for custom field values.
 * Accepts raw JSON strings and parses them to the appropriate type.
 * Examples:
 * - "hello" -> string
 * - 123 -> number
 * - true -> boolean
 * - ["a", "b"] -> array
 * - null -> null
 */
export function JsonInput({
  value,
  onChange,
  disabled = false,
  className,
  placeholder = 'e.g., "text", 123, ["a","b"], true',
  multiline = false,
}: JsonInputProps) {
  // Store the raw string value for editing
  const [rawValue, setRawValue] = useState<string>(() => {
    if (value === undefined || value === null) return "";
    if (typeof value === "string") return `"${value}"`;
    return JSON.stringify(value);
  });
  const [error, setError] = useState<string | null>(null);

  // Sync raw value when external value changes
  useEffect(() => {
    if (value === undefined || value === null) {
      setRawValue("");
    } else if (typeof value === "string") {
      setRawValue(`"${value}"`);
    } else {
      setRawValue(JSON.stringify(value));
    }
  }, [value]);

  const handleChange = (newRawValue: string) => {
    setRawValue(newRawValue);

    if (!newRawValue.trim()) {
      setError(null);
      onChange?.(undefined);
      return;
    }

    try {
      // Try to parse as JSON
      const parsed = JSON.parse(newRawValue);
      setError(null);
      onChange?.(parsed as FilterValue);
    } catch {
      // If not valid JSON, treat as plain string (without quotes)
      // This allows users to type simple strings without quotes
      setError('Invalid JSON. Use quotes for strings: "text"');
      // Still pass the raw value as a string for usability
      onChange?.(newRawValue);
    }
  };

  const inputClassName = cn(
    "h-8 font-mono text-sm",
    error && "border-orange-500 focus-visible:ring-orange-500",
    className,
  );

  const InputComponent = multiline ? Textarea : Input;

  return (
    <TooltipProvider>
      <Tooltip open={error ? undefined : false}>
        <TooltipTrigger asChild>
          <div className="relative flex-1">
            <InputComponent
              value={rawValue}
              onChange={(e) => handleChange(e.target.value)}
              placeholder={placeholder}
              disabled={disabled}
              className={inputClassName}
            />
          </div>
        </TooltipTrigger>
        <TooltipContent
          side="bottom"
          className="text-xs"
        >
          <p>{error}</p>
          <p className="text-muted-foreground mt-1">
            Tip: Use &quot;text&quot; for strings, [1,2,3] for arrays
          </p>
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}

import { X } from "lucide-react";
import { useRef, useState } from "react";

import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";

import type { KeyboardEvent } from "react";

export interface MultiValueInputProps {
  value?: (string | number)[];
  onChange?: (value: (string | number)[]) => void;
  placeholder?: string;
  disabled?: boolean;
  className?: string;
  type?: "text" | "number";
}

export function MultiValueInput({
  value = [],
  onChange,
  placeholder = "Type and press Enter...",
  disabled = false,
  className,
  type = "text",
}: MultiValueInputProps) {
  const [inputValue, setInputValue] = useState("");
  const inputRef = useRef<HTMLInputElement>(null);

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter" && inputValue.trim()) {
      e.preventDefault();
      const newValue =
        type === "number" ? Number.parseFloat(inputValue) : inputValue.trim();

      if (type === "number" && Number.isNaN(newValue as number)) {
        return;
      }

      if (!value.includes(newValue)) {
        onChange?.([...value, newValue]);
      }
      setInputValue("");
    } else if (e.key === "Backspace" && !inputValue && value.length > 0) {
      onChange?.(value.slice(0, -1));
    }
  };

  const handleRemove = (index: number) => {
    const newValue = [...value];
    newValue.splice(index, 1);
    onChange?.(newValue);
  };

  return (
    <div
      className={cn(
        "border-input flex min-h-8 w-full flex-wrap items-center gap-1 rounded-md border bg-transparent px-2 py-1 text-sm shadow-xs",
        disabled && "cursor-not-allowed opacity-50",
        className,
      )}
      onClick={() => inputRef.current?.focus()}
    >
      {value.map((v, i) => (
        <Badge
          key={`${String(v)}-${String(i)}`}
          variant="secondary"
          className="gap-1 rounded-sm"
        >
          {v}
          {!disabled && (
            <X
              className="h-3 w-3 cursor-pointer hover:opacity-75"
              onClick={(e) => {
                e.stopPropagation();
                handleRemove(i);
              }}
            />
          )}
        </Badge>
      ))}
      <Input
        ref={inputRef}
        type={type}
        value={inputValue}
        onChange={(e) => setInputValue(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder={value.length === 0 ? placeholder : ""}
        disabled={disabled}
        className="h-6 min-w-[80px] flex-1 border-0 p-0 shadow-none focus-visible:ring-0"
      />
    </div>
  );
}

import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";

export interface NumberInputProps {
  value?: number | string;
  onChange?: (value: number | undefined) => void;
  placeholder?: string;
  disabled?: boolean;
  className?: string;
  min?: number;
  max?: number;
  step?: number;
  allowFloat?: boolean;
}

export function NumberInput({
  value,
  onChange,
  placeholder = "Enter number...",
  disabled = false,
  className,
  min,
  max,
  step = 1,
  allowFloat = true,
}: NumberInputProps) {
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const inputValue = e.target.value;

    if (inputValue === "" || inputValue === "-") {
      onChange?.(undefined);
      return;
    }

    const parsed = allowFloat
      ? Number.parseFloat(inputValue)
      : Number.parseInt(inputValue, 10);

    if (!Number.isNaN(parsed)) {
      onChange?.(parsed);
    }
  };

  return (
    <Input
      type="number"
      value={value ?? ""}
      onChange={handleChange}
      placeholder={placeholder}
      disabled={disabled}
      className={cn("h-8", className)}
      min={min}
      max={max}
      step={step}
    />
  );
}

export interface NumberRangeInputProps {
  value?: [number | undefined, number | undefined];
  onChange?: (value: [number | undefined, number | undefined]) => void;
  placeholder?: [string, string];
  disabled?: boolean;
  className?: string;
  allowFloat?: boolean;
}

export function NumberRangeInput({
  value,
  onChange,
  placeholder = ["From", "To"],
  disabled = false,
  className,
  allowFloat = true,
}: NumberRangeInputProps) {
  const [from, to] = value ?? [undefined, undefined];

  return (
    <div className={cn("flex items-center gap-2", className)}>
      <NumberInput
        value={from}
        onChange={(v) => onChange?.([v, to])}
        placeholder={placeholder[0]}
        disabled={disabled}
        allowFloat={allowFloat}
        className="flex-1"
      />
      <span className="text-muted-foreground text-sm">to</span>
      <NumberInput
        value={to}
        onChange={(v) => onChange?.([from, v])}
        placeholder={placeholder[1]}
        disabled={disabled}
        allowFloat={allowFloat}
        className="flex-1"
      />
    </div>
  );
}

